def tooltip(row):
    return f"{row['region']}: {row['median']} PEN (n={row['n']})"
print(tooltip({"region": "Lima", "median": 28.0, "n": 40}))

def pie(cap):
    return " | ".join(f"{k}: {v}" for k, v in cap.items())
print(pie({"unidad": "PEN", "fuente": "sintetico"}))

